Title: LLM Service with Retry
Description: Production LLM service wrapper with caching, retry, and token tracking
When to use: Any application using LLM APIs
Code Example:
@Service
public class LLMService {
  private final WebClient client;
  private final Cache<String, String> cache = Caffeine.newBuilder().maximumSize(1000).expireAfterWrite(1, TimeUnit.HOURS).build();

  @Retryable(maxAttempts=3, backoff=@Backoff(delay=1000, multiplier=2))
  public String generate(String systemPrompt, String userPrompt) {
    String cacheKey = DigestUtils.sha256Hex(systemPrompt + userPrompt);
    String cached = cache.getIfPresent(cacheKey);
    if (cached != null) return cached;

    String response = client.post().uri("/chat/completions")
      .bodyValue(Map.of("model", "gpt-4", "messages", List.of(
        Map.of("role", "system", "content", systemPrompt),
        Map.of("role", "user", "content", userPrompt)
      ), "temperature", 0))
      .retrieve().bodyToMono(String.class).block();
    cache.put(cacheKey, response);
    return response;
  }
}

