Title: BFS & DFS Templates
Description: Standard BFS and DFS graph traversal templates
When to use: Graph problems, tree traversal, shortest path
Code Example:
// BFS — shortest path in unweighted graph
void bfs(Map<Integer, List<Integer>> graph, int start) {
  Queue<Integer> queue = new LinkedList<>();
  Set<Integer> visited = new HashSet<>();
  queue.offer(start); visited.add(start);
  while (!queue.isEmpty()) {
    int node = queue.poll();
    for (int neighbor : graph.getOrDefault(node, List.of())) {
      if (visited.add(neighbor)) queue.offer(neighbor);
    }
  }
}

// DFS — recursive
void dfs(Map<Integer, List<Integer>> graph, int node, Set<Integer> visited) {
  visited.add(node);
  for (int neighbor : graph.getOrDefault(node, List.of())) {
    if (!visited.contains(neighbor)) dfs(graph, neighbor, visited);
  }
}

