When to use: API gateways and middleware
Code Example:
// Spring Boot with Bucket4j
@Component class RateLimitFilter extends OncePerRequestFilter {
  private final Map<String, Bucket> buckets = new ConcurrentHashMap<>();
  private Bucket resolveBucket(String key) {
    return buckets.computeIfAbsent(key, k -> Bucket.builder()
      .addLimit(Bandwidth.classic(100, Refill.intervally(100, Duration.ofMinutes(1))))
      .build());
  }
  @Override protected void doFilterInternal(HttpServletRequest req, HttpServletResponse res, FilterChain chain) {
    String key = req.getRemoteAddr();
    Bucket bucket = resolveBucket(key);
    if (bucket.tryConsume(1)) { chain.doFilter(req, res); }
    else { res.setStatus(429); res.setHeader("Retry-After", "60"); res.getWriter().write("{\"error\":\"Too many requests\"}"); }
  }
}

