Title: JUnit 5 Service Test
Description: Complete unit test for a Spring service with mocks, assertions, and edge cases
When to use: Testing service layer in Spring Boot
Code Example:
@ExtendWith(MockitoExtension.class)
class UserServiceTest {
    @Mock UserRepository repo;
    @Mock PasswordEncoder encoder;
    @InjectMocks UserService service;

    @Test void create_shouldSaveUser() {
        var dto = new CreateUserDTO("John", "j@x.com", "pass123");
        when(repo.existsByEmail("j@x.com")).thenReturn(false);
        when(encoder.encode("pass123")).thenReturn("hashed");
        when(repo.save(any())).thenAnswer(inv -> { User u = inv.getArgument(0); u.setId(1L); return u; });

        var result = service.create(dto);

        assertThat(result.getId()).isEqualTo(1L);
        assertThat(result.getEmail()).isEqualTo("j@x.com");
        verify(repo).save(argThat(u -> u.getPassword().equals("hashed")));
    }

    @Test void create_shouldThrow_whenEmailExists() {
        when(repo.existsByEmail("j@x.com")).thenReturn(true);
        assertThrows(DuplicateException.class, () -> service.create(new CreateUserDTO("John","j@x.com","pass")));
    }
}

