Title: API Integration Test
Description: Full API integration test with database, authentication, and cleanup
When to use: Testing REST APIs end-to-end
Code Example:
@SpringBootTest(webEnvironment = RANDOM_PORT)
@Testcontainers
class UserApiIntegrationTest {
    @Container static PostgreSQLContainer<?> pg = new PostgreSQLContainer<>("postgres:16");
    @Autowired TestRestTemplate rest;
    @Autowired UserRepository repo;

    @BeforeEach void setup() { repo.deleteAll(); }

    @Test void fullCrudFlow() {
        // Create
        var createResp = rest.postForEntity("/api/v1/users", new CreateUserDTO("John","j@x.com","pass"), UserDTO.class);
        assertThat(createResp.getStatusCode()).isEqualTo(HttpStatus.CREATED);
        Long id = createResp.getBody().getId();

        // Read
        var getResp = rest.getForEntity("/api/v1/users/" + id, UserDTO.class);
        assertThat(getResp.getBody().getName()).isEqualTo("John");

        // Update
        rest.put("/api/v1/users/" + id, new UpdateUserDTO("Jane"));

        // Delete
        rest.delete("/api/v1/users/" + id);
        assertThat(rest.getForEntity("/api/v1/users/" + id, String.class).getStatusCode()).isEqualTo(HttpStatus.NOT_FOUND);
    }
}
